import{_ as e,c as t,o as i,a}from"./app.aaf606c4.js";const f='{"title":"Introduction","description":"","frontmatter":{},"headers":[{"level":2,"title":"What is SCALE?","slug":"what-is-scale"},{"level":2,"title":"Project Architecture","slug":"project-architecture"}],"relativePath":"guide/introduction.md"}',o={},r=a('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-hidden="true">#</a></h1><h2 id="what-is-scale" tabindex="-1">What is SCALE? <a class="header-anchor" href="#what-is-scale" aria-hidden="true">#</a></h2><p>SCALE is an abbreviation for Simple Concatenated Aggregate Little-Endian, and it is a lightweight, efficient, binary serialization and deserialization codec. Originally it comes from <a href="https://docs.substrate.io/v3/advanced/scale-codec/" target="_blank" rel="noopener noreferrer">Substrate</a>. Besides from Substrate, it is generally useful if you need to efficiently communitate with Rust backend due to Codec&#39;s Enum support.</p><h2 id="project-architecture" tabindex="-1">Project Architecture <a class="header-anchor" href="#project-architecture" aria-hidden="true">#</a></h2><p>From low to high:</p><ul><li>Enum library. Rust Enum is not the most trivial thing to work with in TypeScript. This package provides a lightweight class to work with it. Enum codecs in core package built on top of it.</li><li>Core library. It provides a set of functions designed to implement encoding &amp; decoding of any SCALE-spec-compatible primitive or structure in the most efficient way. It is quite low-level and does not provide a lot of conveniences to work with large type namespaces from scratch, but it can be used to build such conveniences with.</li><li>Definition libraries, compiler &amp; its runtime. Helps to deal with large namespaces.</li></ul><p>Firstly, let&#39;s overview how Enums does work.</p>',7),n=[r];function c(s,l,d,h,u,p){return i(),t("div",null,n)}var _=e(o,[["render",c]]);export{f as __pageData,_ as default};
